				                        targetCompletionDate: String(item?.original_expiry_date || item?.target_completion_date || "").trim(),
				                        revisedCompletionDate: String(item?.revised_expiry_date || item?.revised_completion_date || "").trim(),
				                        status: mappedStatus,
